     1вҶ’#Requires -Version 5.1
     2вҶ’<#
     3вҶ’.SYNOPSIS
     4вҶ’    Bootstrap Personal Claude Environment - works on Home, Work, and Laptop.
     5вҶ’
     6вҶ’.DESCRIPTION
     7вҶ’    Creates symlinks from ~/.claude/ to personal-claude-docs enterprise layer.
     8вҶ’    Also wires Obsidian vault _claude-* folders to the same targets.
     9вҶ’
    10вҶ’    Source of truth:   personal-claude-docs/.claude/enterprise/  (this repo)
    11вҶ’    Claude reads from: ~/.claude/{commands,skills,learning,reference,agents}
    12вҶ’    Obsidian sees:     {vault}/0X-{Section}/_claude-{name}  (same real dirs)
    13вҶ’
    14вҶ’    Auto-detects computer profile by OneDrive location.
    15вҶ’    Falls back to directory junctions when symlinks require elevation.
    16вҶ’
    17вҶ’.PARAMETER Profile
    18вҶ’    Computer profile: "home" | "work" | "laptop" | "auto" (default: auto)
    19вҶ’
    20вҶ’.PARAMETER Force
    21вҶ’    Remove and recreate existing symlinks/junctions.
    22вҶ’
    23вҶ’.PARAMETER BackupExisting
    24вҶ’    Backup real directories in ~/.claude/ before replacing with symlinks.
    25вҶ’
    26вҶ’.EXAMPLE
    27вҶ’    .\setup-personal.ps1
    28вҶ’    .\setup-personal.ps1 -Force
    29вҶ’    .\setup-personal.ps1 -Profile work -Force
    30вҶ’#>
    31вҶ’
    32вҶ’[CmdletBinding()]
    33вҶ’param(
    34вҶ’    [ValidateSet("auto","home","work","laptop")]
    35вҶ’    [string]$Profile = "auto",
    36вҶ’
    37вҶ’    [switch]$Force,
    38вҶ’    [switch]$BackupExisting
    39вҶ’)
    40вҶ’
    41вҶ’$ErrorActionPreference = "Stop"
    42вҶ’
    43вҶ’function Write-Step    { param([string]$m) Write-Host "  -> $m" -ForegroundColor Cyan }
    44вҶ’function Write-Ok      { param([string]$m) Write-Host "  OK  $m" -ForegroundColor Green }
    45вҶ’function Write-Skip    { param([string]$m) Write-Host "  --  $m" -ForegroundColor Gray }
    46вҶ’function Write-Warn    { param([string]$m) Write-Host "  !!  $m" -ForegroundColor Yellow }
    47вҶ’function Write-Fail    { param([string]$m) Write-Host "  XX  $m" -ForegroundColor Red }
    48вҶ’
    49вҶ’Write-Host ""
    50вҶ’Write-Host "============================================" -ForegroundColor Blue
    51вҶ’Write-Host "  Personal Claude Environment - Bootstrap  " -ForegroundColor Blue
    52вҶ’Write-Host "============================================" -ForegroundColor Blue
    53вҶ’Write-Host ""
    54вҶ’
    55вҶ’# в”Җв”Җв”Җ 1. Detect profile в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    56вҶ’
    57вҶ’if ($Profile -eq "auto") {
    58вҶ’    # Detect by username (more reliable than vault path since OneDrive syncs both)
    59вҶ’    $currentUser = $env:USERNAME
    60вҶ’    if     ($currentUser -eq "eduar")    { $Profile = "home" }
    61вҶ’    elseif ($currentUser -eq "emarquez") { $Profile = "work" }
    62вҶ’    else {
    63вҶ’        Write-Warn "Cannot auto-detect profile for user: $currentUser"
    64вҶ’        Write-Host "  Use -Profile home|work|laptop explicitly" -ForegroundColor Gray
    65вҶ’        Write-Host "  Expected usernames: eduar (home) | emarquez (work)" -ForegroundColor Gray
    66вҶ’        exit 1
    67вҶ’    }
    68вҶ’}
    69вҶ’
    70вҶ’switch ($Profile) {
    71вҶ’    "home" {
    72вҶ’        $claudeRoot  = "C:\Users\eduar\.claude"
    73вҶ’        $vaultPath   = "D:\OneDrive\16 - Obsidian\01_Claude_Home"
    74вҶ’    }
    75вҶ’    "work" {
    76вҶ’        $claudeRoot  = "C:\Users\emarquez\.claude"
    77вҶ’        $vaultPath   = "C:\Users\emarquez\OneDrive\16 - Obsidian\00_Claude"
    78вҶ’    }
    79вҶ’    "laptop" {
    80вҶ’        $claudeRoot  = "$env:USERPROFILE\.claude"
    81вҶ’        $vaultPath   = "$env:USERPROFILE\OneDrive\16 - Obsidian\01_Claude_Home"
    82вҶ’    }
    83вҶ’}
    84вҶ’
    85вҶ’# Repo root = two levels up from this script (.claude/scripts/ -> .claude/ -> repo root)
    86вҶ’$repoRoot        = Split-Path (Split-Path $PSScriptRoot -Parent) -Parent
    87вҶ’$enterpriseSrc   = Join-Path $repoRoot ".claude\enterprise"
    88вҶ’$personalSrc     = Join-Path $repoRoot ".claude\users\emarquez-personal"
    89вҶ’
    90вҶ’Write-Host "  Profile    : $Profile"
    91вҶ’Write-Host "  Repo       : $repoRoot"
    92вҶ’Write-Host "  Claude dir : $claudeRoot"
    93вҶ’Write-Host "  Vault      : $vaultPath"
    94вҶ’Write-Host ""
    95вҶ’
    96вҶ’# в”Җв”Җв”Җ 2. Preflight в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    97вҶ’
    98вҶ’$canSymlink = $false
    99вҶ’try {
   100вҶ’    $isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole(
   101вҶ’        [Security.Principal.WindowsBuiltInRole]::Administrator)
   102вҶ’    $devMode = (Get-ItemProperty "HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\AppModelUnlock" `
   103вҶ’        -ErrorAction SilentlyContinue).AllowDevelopmentWithoutDevLicense -eq 1
   104вҶ’    $canSymlink = $isAdmin -or $devMode
   105вҶ’} catch {}
   106вҶ’
   107вҶ’$linkMethod = if ($canSymlink) { "symlink" } else { "junction (no admin - fallback)" }
   108вҶ’Write-Host "  Link method: $linkMethod" -ForegroundColor $(if ($canSymlink) { "Green" } else { "Yellow" })
   109вҶ’Write-Host ""
   110вҶ’
   111вҶ’if (-not (Test-Path $claudeRoot)) {
   112вҶ’    Write-Fail "Claude dir not found: $claudeRoot"
   113вҶ’    Write-Host "  Run Claude Code once to initialize it." -ForegroundColor Gray
   114вҶ’    exit 1
   115вҶ’}
   116вҶ’if (-not (Test-Path $enterpriseSrc)) {
   117вҶ’    Write-Fail "Enterprise source not found: $enterpriseSrc"
   118вҶ’    Write-Host "  Clone personal-claude-docs first." -ForegroundColor Gray
   119вҶ’    exit 1
   120вҶ’}
   121вҶ’
   122вҶ’# в”Җв”Җв”Җ 3. Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   123вҶ’
   124вҶ’function Set-Link {
   125вҶ’    param([string]$LinkPath, [string]$Target, [string]$Label)
   126вҶ’
   127вҶ’    if (-not (Test-Path $Target)) {
   128вҶ’        Write-Warn "$Label : target missing ($Target)"
   129вҶ’        return
   130вҶ’    }
   131вҶ’
   132вҶ’    if (Test-Path $LinkPath) {
   133вҶ’        $existing = Get-Item $LinkPath -Force
   134вҶ’        $isLink   = $existing.Attributes -band [IO.FileAttributes]::ReparsePoint
   135вҶ’
   136вҶ’        if ($Force) {
   137вҶ’            if ($isLink) {
   138вҶ’                # Remove junction/symlink without touching target contents
   139вҶ’                try {
   140вҶ’                    [System.IO.Directory]::Delete($LinkPath)
   141вҶ’                } catch {
   142вҶ’                    try { Remove-Item $LinkPath -Force -ErrorAction Stop }
   143вҶ’                    catch { Write-Warn "$Label : could not remove existing link - $_"; return }
   144вҶ’                }
   145вҶ’            } else {
   146вҶ’                # Real directory - backup if has content, delete if empty
   147вҶ’                $isEmpty = (@(Get-ChildItem $LinkPath -Force -ErrorAction SilentlyContinue)).Count -eq 0
   148вҶ’                if ($isEmpty) {
   149вҶ’                    Remove-Item $LinkPath -Force -Recurse
   150вҶ’                } elseif ($BackupExisting) {
   151вҶ’                    $bk = "$LinkPath.bak-$(Get-Date -Format 'yyyyMMdd-HHmmss')"
   152вҶ’                    Rename-Item $LinkPath $bk
   153вҶ’                    Write-Ok "$Label : backed up to $(Split-Path $bk -Leaf)"
   154вҶ’                } else {
   155вҶ’                    Write-Warn "$Label : real directory with content - use -Force -BackupExisting to replace"
   156вҶ’                    return
   157вҶ’                }
   158вҶ’            }
   159вҶ’        } else {
   160вҶ’            if ($isLink) { Write-Skip "$Label : already linked" }
   161вҶ’            else         { Write-Warn "$Label : real directory exists (use -Force to replace)" }
   162вҶ’            return
   163вҶ’        }
   164вҶ’    }
   165вҶ’
   166вҶ’    $parent = Split-Path $LinkPath -Parent
   167вҶ’    if (-not (Test-Path $parent)) { New-Item -ItemType Directory -Path $parent -Force | Out-Null }
   168вҶ’
   169вҶ’    if ($existing.PSIsContainer -or (Test-Path $Target -PathType Container)) {
   170вҶ’        # Directory link
   171вҶ’        if ($canSymlink) {
   172вҶ’            New-Item -ItemType SymbolicLink -Path $LinkPath -Target $Target -Force | Out-Null
   173вҶ’        } else {
   174вҶ’            cmd /c mklink /J "$LinkPath" "$Target" 2>&1 | Out-Null
   175вҶ’        }
   176вҶ’    } else {
   177вҶ’        # File link
   178вҶ’        if ($canSymlink) {
   179вҶ’            New-Item -ItemType SymbolicLink -Path $LinkPath -Target $Target -Force | Out-Null
   180вҶ’        } else {
   181вҶ’            Copy-Item $Target $LinkPath -Force
   182вҶ’            Write-Warn "$Label : copied (file symlinks need admin - re-run as admin for live link)"
   183вҶ’            return
   184вҶ’        }
   185вҶ’    }
   186вҶ’
   187вҶ’    if (Test-Path $LinkPath) { Write-Ok "$Label" }
   188вҶ’    else                     { Write-Fail "$Label : creation failed" }
   189вҶ’}
   190вҶ’
   191вҶ’# в”Җв”Җв”Җ 4. ~/.claude/ symlinks в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   192вҶ’
   193вҶ’Write-Step "Linking ~/.claude/ -> enterprise dirs"
   194вҶ’Set-Link "$claudeRoot\commands"   "$enterpriseSrc\commands"  "commands"
   195вҶ’Set-Link "$claudeRoot\skills"     "$enterpriseSrc\skills"    "skills"
   196вҶ’Set-Link "$claudeRoot\learning"   "$enterpriseSrc\learning"  "learning"
   197вҶ’Set-Link "$claudeRoot\reference"  "$enterpriseSrc\reference" "reference"
   198вҶ’Set-Link "$claudeRoot\agents"     "$enterpriseSrc\agents"    "agents"
   199вҶ’Set-Link "$claudeRoot\enterprise" "$enterpriseSrc"           "enterprise (for @-imports)"
   200вҶ’Set-Link "$claudeRoot\personal"   "$personalSrc"             "personal   (for @-imports)"
   201вҶ’
   202вҶ’# в”Җв”Җв”Җ 5. ~/.claude/CLAUDE.md в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   203вҶ’
   204вҶ’Write-Host ""
   205вҶ’Write-Step "Setting up CLAUDE.md"
   206вҶ’$claudeMdTarget = "$claudeRoot\CLAUDE.md"
   207вҶ’$claudeMdSource = "$enterpriseSrc\CLAUDE.md"
   208вҶ’
   209вҶ’if ((Test-Path $claudeMdTarget) -and -not $Force) {
   210вҶ’    Write-Skip "CLAUDE.md : already exists (use -Force to regenerate)"
   211вҶ’} else {
   212вҶ’    if (Test-Path $claudeMdTarget) { Remove-Item $claudeMdTarget -Force }
   213вҶ’
   214вҶ’    $machineName = switch ($Profile) {
   215вҶ’        "home"   { "Home (eduar)" }
   216вҶ’        "work"   { "Work (emarquez)" }
   217вҶ’        "laptop" { "Laptop ($env:USERNAME)" }
   218вҶ’    }
   219вҶ’    $oneDrive = switch ($Profile) {
   220вҶ’        "home"   { "D:\OneDrive\" }
   221вҶ’        "work"   { "C:\Users\emarquez\OneDrive\" }
   222вҶ’        "laptop" { "$env:USERPROFILE\OneDrive\" }
   223вҶ’    }
   224вҶ’
   225вҶ’@"
   226вҶ’# Claude Global Config - $machineName
   227вҶ’# Auto-generated by setup-personal.ps1 - edit enterprise/CLAUDE.md for shared config.
   228вҶ’
   229вҶ’@enterprise/CLAUDE.md
   230вҶ’@personal/CLAUDE.md
   231вҶ’
   232вҶ’---
   233вҶ’
   234вҶ’## Machine: $machineName
   235вҶ’
   236вҶ’| Item | Path |
   237вҶ’|------|------|
   238вҶ’| OneDrive | ``$oneDrive`` |
   239вҶ’| Obsidian vault | ``$vaultPath`` |
   240вҶ’| ClaudeDocs | ``$repoRoot`` |
   241вҶ’| Claude dir | ``$claudeRoot`` |
   242вҶ’
   243вҶ’### New Machine Setup
   244вҶ’``````powershell
   245вҶ’git clone https://github.com/Eduardodmb/ClaudeDocs.git "`$env:USERPROFILE\personal-claude-docs"
   246вҶ’& "`$env:USERPROFILE\personal-claude-docs\.claude\scripts\setup-personal.ps1"
   247вҶ’``````
   248вҶ’"@ | Out-File $claudeMdTarget -Encoding utf8
   249вҶ’
   250вҶ’    Write-Ok "CLAUDE.md : generated with @enterprise and @personal imports"
   251вҶ’}
   252вҶ’
   253вҶ’# в”Җв”Җв”Җ 6. Runtime dirs (local only) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   254вҶ’
   255вҶ’Write-Host ""
   256вҶ’Write-Step "Ensuring runtime directories"
   257вҶ’foreach ($d in @("state","worktrees")) {
   258вҶ’    $p = "$claudeRoot\$d"
   259вҶ’    if (-not (Test-Path $p)) {
   260вҶ’        New-Item -ItemType Directory -Path $p -Force | Out-Null
   261вҶ’        Write-Ok "$d/ created"
   262вҶ’    } else {
   263вҶ’        Write-Skip "$d/ exists"
   264вҶ’    }
   265вҶ’}
   266вҶ’
   267вҶ’# в”Җв”Җв”Җ 7. Install .setup/ scripts в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   268вҶ’
   269вҶ’Write-Host ""
   270вҶ’Write-Step "Installing .setup/ scripts"
   271вҶ’
   272вҶ’$setupDir     = "$claudeRoot\.setup"
   273вҶ’$scriptsSrc   = $PSScriptRoot
   274вҶ’
   275вҶ’if (-not (Test-Path $setupDir)) {
   276вҶ’    New-Item -ItemType Directory -Path $setupDir -Force | Out-Null
   277вҶ’}
   278вҶ’
   279вҶ’foreach ($scriptName in @("claude-session.ps1", "sidebar.ps1")) {
   280вҶ’    $src  = Join-Path $scriptsSrc $scriptName
   281вҶ’    $dest = Join-Path $setupDir   $scriptName
   282вҶ’    if (Test-Path $src) {
   283вҶ’        Copy-Item $src $dest -Force
   284вҶ’        Write-Ok ".setup/$scriptName"
   285вҶ’    } else {
   286вҶ’        Write-Warn ".setup/$scriptName : source not found at $src"
   287вҶ’    }
   288вҶ’}
   289вҶ’
   290вҶ’# в”Җв”Җв”Җ 8. PowerShell profile shortcut в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   291вҶ’
   292вҶ’Write-Host ""
   293вҶ’Write-Step "Setting up PowerShell profile shortcut"
   294вҶ’
   295вҶ’try {
   296вҶ’    $profilePath = $PROFILE
   297вҶ’    if ([string]::IsNullOrEmpty($profilePath)) {
   298вҶ’        $profilePath = "$env:USERPROFILE\Documents\PowerShell\Microsoft.PowerShell_profile.ps1"
   299вҶ’        Write-Warn "profile : `$PROFILE is empty, using default: $profilePath"
   300вҶ’    }
   301вҶ’
   302вҶ’    $snippet = @'
   303вҶ’
   304вҶ’# в”Җв”Җ Claude Code в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
   305вҶ’function claude-session {
