   327вҶ’        Write-Ok "profile : created $profilePath with shortcut"
   328вҶ’    }
   329вҶ’    Write-Host "  Run 'cs' or 'claude-session' to launch with sidebar." -ForegroundColor DarkGray
   330вҶ’    Write-Host "  Reload with: . `$PROFILE" -ForegroundColor DarkGray
   331вҶ’} catch {
