function Set-Link {
    param([string]$LinkPath, [string]$Target, [string]$Label)

    if (-not (Test-Path $Target)) {
        Write-Warn "$Label : target missing ($Target)"
        return
    }

    if (Test-Path $LinkPath) {
        $existing = Get-Item $LinkPath -Force
        $isLink   = $existing.Attributes -band [IO.FileAttributes]::ReparsePoint

        if ($Force) {
            if ($isLink) {
                # Remove junction/symlink without touching target contents
                try {
                    [System.IO.Directory]::Delete($LinkPath)
                } catch {
                    try { Remove-Item $LinkPath -Force -ErrorAction Stop }
                    catch { Write-Warn "$Label : could not remove existing link - $_"; return }
                }
            } else {
                # Real directory - backup if has content, delete if empty
                $isEmpty = (@(Get-ChildItem $LinkPath -Force -ErrorAction SilentlyContinue)).Count -eq 0
                if ($isEmpty) {
                    Remove-Item $LinkPath -Force -Recurse
                } elseif ($BackupExisting) {
                    $bk = "$LinkPath.bak-$(Get-Date -Format 'yyyyMMdd-HHmmss')"
                    Rename-Item $LinkPath $bk
                    Write-Ok "$Label : backed up to $(Split-Path $bk -Leaf)"
                } else {
                    Write-Warn "$Label : real directory with content - use -Force -BackupExisting to replace"
                    return
                }
            }
        } else {
            if ($isLink) { Write-Skip "$Label : already linked" }
            else         { Write-Warn "$Label : real directory exists (use -Force to replace)" }
            return
        }
    }

    $parent = Split-Path $LinkPath -Parent
    if (-not (Test-Path $parent)) { New-Item -ItemType Directory -Path $parent -Force | Out-Null }

    if ($existing.PSIsContainer -or (Test-Path $Target -PathType Container)) {
        # Directory link
        if ($canSymlink) {
            New-Item -ItemType SymbolicLink -Path $LinkPath -Target $Target -Force | Out-Null
        } else {
            cmd /c mklink /J "$LinkPath" "$Target" 2>&1 | Out-Null
        }
    } else {
        # File link
        if ($canSymlink) {
            New-Item -ItemType SymbolicLink -Path $LinkPath -Target $Target -Force | Out-Null
        } else {
            Copy-Item $Target $LinkPath -Force
            Write-Warn "$Label : copied (file symlinks need admin - re-run as admin for live link)"
            return
        }
    }

    if (Test-Path $LinkPath) { Write-Ok "$Label" }
    else                     { Write-Fail "$Label : creation failed" }
}

